mapper.select:
select tfi.*, te.actual_name as initiatorName from t_flow_instance tfi left join t_employee te on tfi.initiator_id = te.employee_id
and tfi.enterprise_id = #{query.enterpriseId}
and tfi.audit_status in
#{item}
AND ( INSTR(tfi.business_id,#{query.searchWord}) OR INSTR(tfi.business_code,#{query.searchWord}) OR INSTR(tfi.remark,#{query.searchWord}) OR INSTR(tfi.extend_field1,#{query.searchWord}) OR INSTR(tfi.extend_field2,#{query.searchWord}) OR INSTR(tfi.extend_field3,#{query.searchWord}) OR INSTR(tfi.extend_field4,#{query.searchWord}) OR INSTR(tfi.extend_field5,#{query.searchWord}) OR INSTR(te.actual_name,#{query.searchWord}) OR INSTR(tfi.current_handler_names,#{query.searchWord}) )
and tfi.flow_type = #{query.flowType}
and FIND_IN_SET(#{query.handlerId},tfi.current_handlers)
and tfi.initiator_id = #{query.initiatorId}
and DATE_FORMAT(tfi.create_time, '%Y-%m-%d') >= #{query.submitStartDate}
and #{query.submitEndDate} >= DATE_FORMAT(tfi.create_time, '%Y-%m-%d')
and DATE_FORMAT(tfi.finish_time, '%Y-%m-%d') >= #{query.finishStartDate}
and #{query.finishEndDate} >= DATE_FORMAT(tfi.finish_time, '%Y-%m-%d')
ORDER BY tfi.instance_id asc

select DISTINCT tfi.*, te.actual_name as initiatorName from t_flow_instance_task_record tfitr left join t_flow_instance tfi on tfitr.instance_id = tfi.instance_id left join t_employee te on tfi.initiator_id = te.employee_id
and tfitr.enterprise_id = #{query.enterpriseId}
and tfi.audit_status in
#{item}
AND ( INSTR(tfi.business_id,#{query.searchWord}) OR INSTR(tfi.business_code,#{query.searchWord}) OR INSTR(tfi.remark,#{query.searchWord}) OR INSTR(tfi.extend_field1,#{query.searchWord}) OR INSTR(tfi.extend_field2,#{query.searchWord}) OR INSTR(tfi.extend_field3,#{query.searchWord}) OR INSTR(tfi.extend_field4,#{query.searchWord}) OR INSTR(tfi.extend_field5,#{query.searchWord}) OR INSTR(te.actual_name,#{query.searchWord}) OR INSTR(tfi.current_handler_names,#{query.searchWord}) )
and tfi.flow_type = #{query.flowType}
and tfitr.handler = #{query.handlerId}
and DATE_FORMAT(tfi.create_time, '%Y-%m-%d') >= #{query.submitStartDate}
and #{query.submitEndDate} >= DATE_FORMAT(tfi.create_time, '%Y-%m-%d')
and DATE_FORMAT(tfi.finish_time, '%Y-%m-%d') >= #{query.finishStartDate}
and #{query.finishEndDate} >= DATE_FORMAT(tfi.finish_time, '%Y-%m-%d')
ORDER BY tfitr.instance_id DESC
